  68→// Product API functions
  69→export async function getProducts(params: GetProductsParams = {}): Promise<ProductListDto> {
  70→  const searchParams = new URLSearchParams();
  71→  if (params.page) searchParams.set('page', params.page.toString());
  72→  if (params.pageSize) searchParams.set('pageSize', params.pageSize.toString());
  73→  if (params.categoryId) searchParams.set('categoryId', params.categoryId);
  74→  if (params.status) searchParams.set('status', params.status);
  75→  if (params.search) searchParams.set('search', params.search);
  76→  if (params.sortBy) searchParams.set('sortBy', params.sortBy);
  77→  if (params.sortDirection) searchParams.set('sortDirection', params.sortDirection);
  78→
  79→  const response = await fetch(`${API_BASE}/api/catalog/products?${searchParams}`, {
  80→    cache: 'no-store',
  81→  });
  82→
  83→  if (!response.ok) {
  84→    throw new Error('Failed to fetch products');
  85→  }
  86→
  87→  return response.json();
  88→}
