 21→export function ApiTest() {
 22→  const { data: session } = useSession();
 23→  const [userInfo, setUserInfo] = useState<UserInfo | null>(null);
 24→  const [weather, setWeather] = useState<WeatherForecast[] | null>(null);
 25→  const [error, setError] = useState<string | null>(null);
 26→  const [loading, setLoading] = useState(false);
 27→  const [apiBaseUrl, setApiBaseUrl] = useState<string>("http://localhost:5182");
 28→
 29→  // Fetch API URL from server config (handles Aspire-injected env vars)
 30→  useEffect(() => {
 31→    fetch("/api/config")
 32→      .then((res) => res.json())
 33→      .then((data) => setApiBaseUrl(data.apiBaseUrl))
 34→      .catch(() => {
 35→        // Fallback already set
 36→      });
 37→  }, []);
 38→
 39→  const fetchWithAuth = async (endpoint: string) => {
 40→    if (!session?.accessToken) {
 41→      setError("No access token available. Please sign in.");
 42→      return null;
 43→    }
 44→
 45→    const response = await fetch(`${apiBaseUrl}${endpoint}`, {
 46→      headers: {
 47→        Authorization: `Bearer ${session.accessToken}`,
 48→        "Content-Type": "application/json",
 49→      },
 50→    });
 51→
 52→    if (!response.ok) {
 53→      throw new Error(`API error: ${response.status} ${response.statusText}`);
 54→    }
 55→
 56→    return response.json();
 57→  };
 58→
 59→  const handleFetchMe = async () => {
 60→    setLoading(true);
 61→    setError(null);
 62→    try {
 63→      const data = await fetchWithAuth("/me");
 64→      setUserInfo(data);
 65→    } catch (err) {
 66→      setError(err instanceof Error ? err.message : "Failed to fetch user info");
 67→    } finally {
 68→      setLoading(false);
 69→    }
 70→  };
 71→
 72→  const handleFetchWeather = async () => {
 73→    setLoading(true);
 74→    setError(null);
 75→    try {
 76→      const data = await fetchWithAuth("/weatherforecast");
 77→      setWeather(data);
 78→    } catch (err) {
 79→      setError(err instanceof Error ? err.message : "Failed to fetch weather");
 80→    } finally {
 81→      setLoading(false);
 82→    }
 83→  };
 84→
 85→  if (!session) {
 86→    return (
 87→      <div className="rounded-lg border border-zinc-200 bg-zinc-50 p-6 dark:border-zinc-800 dark:bg-zinc-900">
 88→        <p className="text-zinc-600 dark:text-zinc-400">
 89→          Sign in to test the API endpoints
 90→        </p>
 91→      </div>
 92→    );
 93→  }
 94→
 95→  return (
 96→    <div className="w-full space-y-4">
 97→      <div className="flex gap-3">
 98→        <button
 99→          onClick={handleFetchMe}
100→          disabled={loading}
101→          className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-blue-700 disabled:opacity-50"
102→        >
103→          {loading ? "Loading..." : "GET /me"}
104→        </button>
105→        <button
106→          onClick={handleFetchWeather}
107→          disabled={loading}
108→          className="rounded-lg bg-green-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-green-700 disabled:opacity-50"
109→        >
110→          {loading ? "Loading..." : "GET /weatherforecast"}
111→        </button>
112→      </div>
113→
114→      {error && (
115→        <div className="rounded-lg border border-red-200 bg-red-50 p-4 text-red-700 dark:border-red-900 dark:bg-red-950 dark:text-red-400">
116→          <strong>Error:</strong> {error}
117→        </div>
118→      )}
119→
120→      {userInfo && (
121→        <div className="rounded-lg border border-zinc-200 bg-white p-4 dark:border-zinc-800 dark:bg-zinc-900">
122→          <h3 className="mb-3 font-semibold text-zinc-900 dark:text-zinc-100">
123→            User Info from API
124→          </h3>
125→          <dl className="space-y-2 text-sm">
126→            <div className="flex gap-2">
127→              <dt className="font-medium text-zinc-600 dark:text-zinc-400">Authenticated:</dt>
128→              <dd className="text-zinc-900 dark:text-zinc-100">
129→                {userInfo.isAuthenticated ? "✅ Yes" : "❌ No"}
130→              </dd>
131→            </div>
132→            <div className="flex gap-2">
133→              <dt className="font-medium text-zinc-600 dark:text-zinc-400">Name:</dt>
134→              <dd className="text-zinc-900 dark:text-zinc-100">{userInfo.name || "N/A"}</dd>
135→            </div>
136→            <div className="flex gap-2">
137→              <dt className="font-medium text-zinc-600 dark:text-zinc-400">Email:</dt>
138→              <dd className="text-zinc-900 dark:text-zinc-100">{userInfo.email || "N/A"}</dd>
139→            </div>
140→            <div className="flex gap-2">
141→              <dt className="font-medium text-zinc-600 dark:text-zinc-400">Subject:</dt>
142→              <dd className="font-mono text-xs text-zinc-900 dark:text-zinc-100">
