 61→  const { data: productIds } = useWishlistProductIds();
 62→
 63→  const isInWishlist = productIds?.has(productId) ?? false;
 64→
 65→  const addMutation = useMutation({
 66→    mutationFn: () => {
 67→      if (!session?.accessToken) throw new Error("No access token");
 68→      return addToWishlist(session.accessToken, productId);
 69→    },
 70→    onMutate: async () => {
 71→      await queryClient.cancelQueries({ queryKey: WISHLIST_PRODUCT_IDS_QUERY_KEY });
 72→
 73→      const previousProductIds = queryClient.getQueryData<Set<string>>(
 74→        WISHLIST_PRODUCT_IDS_QUERY_KEY
 75→      );
 76→
 77→      queryClient.setQueryData<Set<string>>(WISHLIST_PRODUCT_IDS_QUERY_KEY, (old) => {
