 79→        newSet.add(productId);
 80→        return newSet;
 81→      });
 82→
 83→      return { previousProductIds };
 84→    },
 85→    onError: (_err, _vars, context) => {
 86→      if (context?.previousProductIds !== undefined) {
 87→        queryClient.setQueryData(WISHLIST_PRODUCT_IDS_QUERY_KEY, context.previousProductIds);
 88→      }
 89→    },
 90→    onSettled: () => {
 91→      queryClient.invalidateQueries({ queryKey: [WISHLIST_QUERY_KEY[0]] });
 92→    },
 93→  });
 94→
 95→  const removeMutation = useMutation({
 96→    mutationFn: () => {
 97→      if (!session?.accessToken) throw new Error("No access token");
 98→      return removeFromWishlist(session.accessToken, productId);
 99→    },
100→    onMutate: async () => {
101→      await queryClient.cancelQueries({ queryKey: WISHLIST_PRODUCT_IDS_QUERY_KEY });
102→
103→      const previousProductIds = queryClient.getQueryData<Set<string>>(
104→        WISHLIST_PRODUCT_IDS_QUERY_KEY
105→      );
106→
107→      queryClient.setQueryData<Set<string>>(WISHLIST_PRODUCT_IDS_QUERY_KEY, (old) => {
108→        const newSet = new Set(old);
109→        newSet.delete(productId);
110→        return newSet;
111→      });
112→
113→      return { previousProductIds };
114→    },
115→    onError: (_err, _vars, context) => {
116→      if (context?.previousProductIds !== undefined) {
117→        queryClient.setQueryData(WISHLIST_PRODUCT_IDS_QUERY_KEY, context.previousProductIds);
118→      }
119→    },
120→    onSettled: () => {
121→      queryClient.invalidateQueries({ queryKey: [WISHLIST_QUERY_KEY[0]] });
122→    },
123→  });
124→
125→  const toggle = () => {
126→    if (isInWishlist) {
127→      removeMutation.mutate();
128→    } else {
129→      addMutation.mutate();
130→    }
131→  };
132→
133→  return {
134→    toggle,
135→    isInWishlist,
136→    isPending: addMutation.isPending || removeMutation.isPending,
137→  };
138→}
